mapper.select:
select s.id, s.user_id, s.follower_count, s.following_count, s.like_count, s.updated_at, IFNULL(m.idno, '') AS user_idno, IFNULL(m.nickname, '') AS user_nickname from t_piamom_user_profile_stat s left join t_member m on m.id = s.user_id
order by ${orderBy} order by s.updated_at desc
limit #{pageNo}, #{pageSize}
